select public.seed_structured_concept('expansion-batch-07','lamotrigine','Pharmacology','lamotrigine therapy','a client recently started dose titration','Titrate slowly and stop and seek urgent evaluation for concerning rash or mucosal lesions','Follow the titration exactly and report any new rash, blister, fever, or mouth sore','Blistering rash with facial swelling and oral lesions','Restart at the full dose after a long interruption','Increase rapidly for faster effect','Cover a new rash and continue','Pharmacological and Parenteral Therapies');
select public.seed_structured_concept('expansion-batch-07','allopurinol','Pharmacology','allopurinol therapy','urate-lowering treatment for recurrent gout','Review renal function and interactions and stop for serious rash or hypersensitivity signs','Take consistently with prescribed hydration and understand it does not treat immediate attack pain','Rash, fever, facial swelling, and liver injury','Double the dose during an acute flare','Continue through a blistering rash','Use with interacting azathioprine without adjustment','Pharmacological and Parenteral Therapies');
select public.seed_structured_concept('expansion-batch-07','epoetin','Pharmacology','epoetin alfa therapy','anemia of chronic kidney disease treated with an erythropoiesis-stimulating agent','Verify hemoglobin, iron status, blood pressure, and thrombosis risk before dosing','Keep laboratory and blood-pressure checks and report chest pain, severe headache, or unilateral swelling','Rapid hemoglobin rise with severe hypertension and neurologic symptoms','Give for uncontrolled hypertension','Target a normal high hemoglobin routinely','Skip iron evaluation','Pharmacological and Parenteral Therapies');
select public.seed_structured_concept('expansion-batch-07','filgrastim','Pharmacology','filgrastim therapy','chemotherapy-related neutropenia','Monitor absolute neutrophil count, timing, bone pain, and splenic or respiratory symptoms','Report left-upper-abdominal or shoulder pain, severe breathing difficulty, or allergic symptoms','Left-upper-quadrant pain with hypotension','Give too close to cytotoxic chemotherapy against protocol','Ignore respiratory distress','Shake the prefilled syringe vigorously','Pharmacological and Parenteral Therapies');

-- Reduction of Risk Potential
