select public.seed_structured_concept('expansion-batch-07','craniotomy-postop','Medical-Surgical','post-craniotomy neurologic deterioration','a client returns after intracranial surgery','Perform frequent neurologic and airway assessment while maintaining ordered head alignment and seizure precautions','Report worsening headache, vomiting, weakness, confusion, seizure, or clear drainage immediately','New unequal pupils with decreasing consciousness','Flex the neck sharply','Place flat despite increased-pressure risk','Delay reporting a seizure','Reduction of Risk Potential');
select public.seed_structured_concept('expansion-batch-07','nephrectomy-postop','Medical-Surgical','complications after nephrectomy','a client has one remaining kidney after surgery','Monitor urine output, renal function, bleeding, respiratory status, and flank incision','Protect kidney health and report reduced urine, fever, increasing pain, or wound drainage','Oliguria with rising creatinine and hypotension','Give nephrotoxic medicine without review','Ignore low urine because one kidney was removed','Encourage dehydration','Reduction of Risk Potential');
select public.seed_structured_concept('expansion-batch-07','amputation-postop','Medical-Surgical','post-amputation complications','a client has residual-limb pain and immobility risk','Assess bleeding, perfusion, positioning, contracture prevention, pain, and phantom sensation','Use prescribed positioning and exercises and report wound change or uncontrolled pain','Rapidly saturating dressing with hypotension','Keep the hip flexed continuously','Place a pillow under the residual limb long term','Dismiss phantom pain as imaginary','Reduction of Risk Potential');
