-- Physiological Adaptation
select public.seed_structured_concept('expansion-batch-07','afib-rvr','Emergency and Critical Care','atrial fibrillation with rapid ventricular response','an irregular rate of 170/min with chest pain and hypotension','Prepare immediate synchronized cardioversion while supporting airway and circulation','Take rate-control and anticoagulant medicines exactly as directed and report syncope, chest pain, or stroke signs','Hypotension and altered consciousness with persistent rapid rhythm','Delay treatment for routine laboratory results','Encourage walking','Use unsynchronized shock for a perfusing rhythm','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-07','hypertensive-emergency','Emergency and Critical Care','hypertensive emergency','severe blood pressure elevation with pulmonary edema and neurologic change','Begin controlled IV blood-pressure reduction with continuous organ-perfusion monitoring','Take medicines consistently and seek emergency care for severe pressure with chest pain, breathlessness, or neurologic symptoms','New seizure and acute pulmonary edema','Lower pressure to normal instantly','Give unmonitored oral doses repeatedly','Delay evaluation because hypertension is often silent','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-07','subarachnoid-hemorrhage','Emergency and Critical Care','subarachnoid hemorrhage','a sudden worst-ever headache, vomiting, neck stiffness, and altered consciousness','Activate neurologic emergency care, protect the airway, and prepare urgent imaging and aneurysm management','Seek emergency help for an abrupt maximal-intensity headache or new neurologic deficit','Declining consciousness with a fixed pupil','Give anticoagulant before imaging','Encourage straining','Delay evaluation if pain improves','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-07','spinal-shock','Emergency and Critical Care','spinal shock after acute cord injury','flaccid paralysis and absent reflexes below the injury with hypotension','Maintain spinal alignment, support ventilation and perfusion, and monitor neurologic return','Prevent skin and respiratory complications and report new breathing difficulty immediately','Progressive respiratory weakness with high cervical injury','Sit upright without stabilization','Use unassisted transfers','Assume absent reflexes prove permanent prognosis','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-07','upper-airway-obstruction','Emergency and Critical Care','acute upper-airway obstruction','inspiratory stridor, retractions, inability to speak, and decreasing air movement','Call emergency support, provide oxygen, and prepare immediate airway intervention','Seek emergency care for stridor, drooling, inability to speak, or blue color','A quiet chest with worsening drowsiness','Inspect deeply with unprepared equipment','Force oral fluids','Leave the client supine and alone','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-07','acute-liver-failure','Medical-Surgical','acute liver failure','jaundice, coagulopathy, hypoglycemia, confusion, and rapidly rising enzymes','Transfer for intensive liver support, monitor glucose and neurologic status, and treat the cause','Avoid unapproved medicines and seek care for jaundice, confusion, bleeding, or severe vomiting','Worsening encephalopathy with hypoglycemia and cerebral-edema signs','Give sedatives for agitation without assessment','Administer hepatotoxic medicine','Delay transplant-center consultation','Physiological Adaptation');

